// api/client.ts

interface RetryConfig {
  maxAttempts: number;
  baseDelayMs: number;
  maxDelayMs: number;
}

async function withRetry<T>(
  fn: () => Promise<T>,
  requestId: string,
  config: RetryConfig = { maxAttempts: 3, baseDelayMs: 1000, maxDelayMs: 30000 }
): Promise<T> {
  for (let attempt = 1; attempt <= config.maxAttempts; attempt++) {
    try {
      const response = await fn();
      // Check if 4xx: if so, throw immediately (no retry)
      if (response.status >= 400 && response.status < 500) {
        return response;
      }
      return response;
    } catch (error) {
      if (attempt === config.maxAttempts) throw error;

      const delay = Math.min(
        config.baseDelayMs * Math.pow(2, attempt - 1),
        config.maxDelayMs
      );
      console.log(`[${requestId}] Retry attempt ${attempt}/${config.maxAttempts} after ${delay}ms`);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

// Wrap existing fetch calls:
export async function fetchData(url: string, options?: RequestInit) {
  const requestId = generateRequestId();
  return withRetry(
    () => fetch(url, options),
    requestId
  );
}
```

